console.log("=== Fix 1: Credential redaction wired into identifier extraction ===");
const sanitizeIdx = src.indexOf('mode: "sanitizeDiagnosticPayload"');
if (sanitizeIdx >= 0) {
  const around = src.slice(Math.max(0, sanitizeIdx - 120), sanitizeIdx + 160);
  console.log(around);
} else {
  console.log("sanitizeDiagnosticPayload call found via import:");
  const importIdx = src.indexOf("sanitizeDiagnosticPayload");
  console.log(src.slice(Math.max(0, importIdx - 40), importIdx + 80));
